import jaximport jax.numpy as npimport numpy as onpimport matplotlib.pyplot as pltfrom jax_fem import loggerlogger.setLevel('ERROR')from jax_fem.generate_mesh import Mesh, get_meshio_cell_type, rectangle_meshfrom jax_fem_pf.problem import PhaseField, Elasticity, PF_Elasticityfrom jax_fem_pf.decompose import Miehefrom jax_fem_pf.solver import stag_ad_wrapperfrom jax_fem_pf.utils import timer, get_dirichlet_load# paramsE = 210e3 nu = 0.3 G_c = 2.4l = 0.05# k = 1e-6# loadingsu_max = 0.01num_steps = 100du = u_max/num_stepsdisps = onp.arange(du, u_max+du, du)full_disps = onp.array([0.] + disps.tolist())# meshele_type = 'QUAD4'cell_type = get_meshio_cell_type(ele_type)Lx, Ly = 1., 1.meshio_mesh = rectangle_mesh(Nx=64, Ny=64, domain_x=Lx, domain_y=Ly)points = meshio_mesh.points - 0.5mesh = Mesh(points, meshio_mesh.cells_dict[cell_type])dim = points.shape[1]# BCsdef top(point):    return np.isclose(point[1], 0.5, atol=1e-3)def bot(point):    return np.isclose(point[1], -0.5, atol=1e-3)def dirichlet_val(point):    return 0.dirichlet_bc_u = [[bot, bot, top, top], [0, 1, 0, 1],                   [dirichlet_val, dirichlet_val, dirichlet_val, get_dirichlet_load(0.)]]# problemdecomp = Miehe(dim)problem_u = Elasticity(mesh, vec=dim, dim=dim, ele_type=ele_type,                        dirichlet_bc_info=dirichlet_bc_u,                       additional_info=(decomp,))problem_d = PhaseField(mesh, vec=1, dim=dim, ele_type=ele_type)problem_ud = PF_Elasticity([mesh]*2, vec=[dim, 1], dim=dim, ele_type=[ele_type]*2,                            dirichlet_bc_info=[dirichlet_bc_u, None],                           additional_info=(decomp,))# wrappersolver_options = {'umfpack_solver':{}}staggered_options = {'tol':1e-5, 'err':'max', 'strict':True}fwd_pred = stag_ad_wrapper(problem_u, problem_d, problem_ud,                           staggered_options,                           solver_options=solver_options,                           adjoint_solver_options=solver_options)#%% SOLVE@timerdef fwd_pred_seq(thetas):        theta_E, theta_nu, theta_G_c, theta_l = thetas        # initialization    sol_u = np.zeros((len(mesh.points), dim))    sol_d = np.zeros((len(mesh.points), 1))    # sol_d = np.where(jax.vmap(crack)(mesh.points), 1., 0.).reshape(-1,1)    history_old = np.zeros((problem_u.fes[0].num_cells, problem_u.fes[0].num_quads))        sols_u = [sol_u]    sols_d = [sol_d]    tractions = [0.]        for step, disp in enumerate(disps):        print(f'STEP={step+1:3d}')        # update displacement loadings        dirichlet_bc_u[-1][-1] = get_dirichlet_load(disp)        problem_u.fes[0].update_Dirichlet_boundary_conditions(dirichlet_bc_u)        # solve        params = [thetas, sol_u, sol_d, history_old]        sol_u, sol_d = fwd_pred(params)        history_old = problem_u.compute_history(sol_u, history_old, theta_E, theta_nu)        traction = problem_u.compute_traction_qd(top, sol_u, sol_d, theta_E, theta_nu)        # traction = problem_u.compute_traction_rs(sol_u, sol_d, theta_E, theta_nu)        # save        sols_u.append(sol_u)        sols_d.append(sol_d)        tractions.append(traction[1])            tractions = np.array(tractions)        return sols_u, sols_d, tractionsif __name__ == '__main__':    thetas = np.array([E, nu, G_c, l])    test_grad = [True, False][1]    if test_grad:        # loss        def loss_fn(xs):            x_E, x_nu, theta_G_c, theta_l = xs            theta_E = x_E * np.ones((len(mesh.cells),1))            theta_nu = x_nu * np.ones((len(mesh.cells),1))            thetas = [theta_E, theta_nu, theta_G_c, theta_l]            _, _, forces = fwd_pred_seq(thetas)            eng = np.trapezoid(forces, full_disps)            return eng        # ad        loss, grads = jax.value_and_grad(loss_fn)(thetas)        # fd        h = 1e-3        vid = 1        ad_grad= grads[vid]        theta0 = thetas[vid].copy()        thetas_fwd = thetas.at[vid].set(theta0*(1+h))        thetas_bwd = thetas.at[vid].set(theta0*(1-h))        loss_fwd = loss_fn(thetas_fwd)        loss_bwd = loss_fn(thetas_bwd)        fd_grad= (loss_fwd-loss_bwd)/(2*h*theta0)        print(f'\nAD gradients:{ad_grad:.6e}')        print(f'FD gradients:{fd_grad:.6e}')    else:        x_E, x_nu, theta_G_c, theta_l = thetas        theta_E = x_E * np.ones((len(mesh.cells),1))        theta_nu = x_nu * np.ones((len(mesh.cells),1))        thetas = [theta_E, theta_nu, theta_G_c, theta_l]        sols_d, sols_u, forces = fwd_pred_seq(thetas)        plt.figure(figsize=(10, 6))        plt.plot(full_disps, forces, 'b--', linewidth=2, label='JAX-FEM')        plt.xlabel('Displacement')        plt.ylabel('Force')        plt.grid(True)        plt.legend()        plt.tight_layout()        plt.show()